const e=JSON.parse('{"key":"v-bfa879e4","path":"/study/%E7%BD%91%E7%BB%9C/WebSocket.html","title":"WebSocket","lang":"zh-CN","frontmatter":{"title":"WebSocket","icon":"wangluo","order":3,"date":"2023-02-27T00:00:00.000Z","category":["网络"],"tag":["WebSocket"],"description":"对WebSocket的理解 WebSocket是HTML5提供的一种浏览器与服务器进行全双工通讯的网络技术，属于应用层协议。它基于TCP传输协议，并复用HTTP的握手通道。浏览器和服务器只需要完成一次握手，两者之间就直接可以创建持久性的连接，并进行双向数据传输。 WebSocket的出现就解决了半双工通信的弊端。它最大的特点是：服务器可以向客户端主动推动消息，客户端也可以主动向服务器推送消息。 WebSocket原理：客户端向WebSocket服务器通知(notify)一个带有所有接收者ID(recipientsIDs)的事件(event),，服务器接收后立即通知所有活跃的(active)客户端，只有D在接收者ID序列中的客户端才会处理这个事件。","head":[["meta",{"property":"og:url","content":"https://luotianxu1.github.io/study/%E7%BD%91%E7%BB%9C/WebSocket.html"}],["meta",{"property":"og:title","content":"WebSocket"}],["meta",{"property":"og:description","content":"对WebSocket的理解 WebSocket是HTML5提供的一种浏览器与服务器进行全双工通讯的网络技术，属于应用层协议。它基于TCP传输协议，并复用HTTP的握手通道。浏览器和服务器只需要完成一次握手，两者之间就直接可以创建持久性的连接，并进行双向数据传输。 WebSocket的出现就解决了半双工通信的弊端。它最大的特点是：服务器可以向客户端主动推动消息，客户端也可以主动向服务器推送消息。 WebSocket原理：客户端向WebSocket服务器通知(notify)一个带有所有接收者ID(recipientsIDs)的事件(event),，服务器接收后立即通知所有活跃的(active)客户端，只有D在接收者ID序列中的客户端才会处理这个事件。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-02-28T05:35:57.000Z"}],["meta",{"property":"article:author","content":"罗天旭"}],["meta",{"property":"article:tag","content":"WebSocket"}],["meta",{"property":"article:published_time","content":"2023-02-27T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-02-28T05:35:57.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"WebSocket\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-02-27T00:00:00.000Z\\",\\"dateModified\\":\\"2024-02-28T05:35:57.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"罗天旭\\",\\"url\\":\\"https://luotianxu1.github.io\\",\\"email\\":\\"1265062404@qq.com\\"}]}"]]},"headers":[{"level":2,"title":"对WebSocket的理解","slug":"对websocket的理解","link":"#对websocket的理解","children":[]},{"level":2,"title":"WebSocket特点","slug":"websocket特点","link":"#websocket特点","children":[]},{"level":2,"title":"即时通讯的实现：短轮询、长轮询、SSE和NWebSocket间的区别","slug":"即时通讯的实现-短轮询、长轮询、sse和nwebsocket间的区别","link":"#即时通讯的实现-短轮询、长轮询、sse和nwebsocket间的区别","children":[]}],"git":{"createdTime":1709098557000,"updatedTime":1709098557000,"contributors":[{"name":"罗天旭","email":"1265062404@qq.com","commits":1}]},"readingTime":{"minutes":4.25,"words":1274},"filePathRelative":"study/网络/WebSocket.md","localizedDate":"2023年2月27日","excerpt":"<h2> 对WebSocket的理解</h2>\\n<p>WebSocket是HTML5提供的一种浏览器与服务器进行全双工通讯的网络技术，属于应用层协议。它基于TCP传输协议，并复用HTTP的握手通道。浏览器和服务器只需要完成一次握手，两者之间就直接可以创建持久性的连接，并进行双向数据传输。</p>\\n<p>WebSocket的出现就解决了半双工通信的弊端。它最大的特点是：服务器可以向客户端主动推动消息，客户端也可以主动向服务器推送消息。</p>\\n<p>WebSocket原理：客户端向WebSocket服务器通知(notify)一个带有所有接收者ID(recipientsIDs)的事件(event),，服务器接收后立即通知所有活跃的(active)客户端，只有D在接收者ID序列中的客户端才会处理这个事件。</p>","autoDesc":true}');export{e as data};
